import { Link } from "react-router-dom";
import { supabase } from "../services/supabaseClient";

export default function Navbar({ user, setUser }) {
  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
  };

  return (
    <div className="flex justify-between items-center px-10 py-4 bg-white shadow-sm">
      <h1 className="text-xl font-bold text-blue-600">
        ResearchMate AI 🚀
      </h1>

      <div className="space-x-4">
        {user ? (
          <>
            <span className="text-gray-600">Hi, {user.email}</span>
            <button 
              className="text-gray-600 hover:text-black" 
              onClick={handleLogout}
            >
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/login" className="text-gray-600 hover:text-black">
              Login
            </Link>
            <Link to="/signup" className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">
              Sign Up
            </Link>
          </>
        )}
      </div>
    </div>
  );
}
